import * as yaml from 'yaml';
import { RuleMetaData } from './types';
import getErrorMessage from '../../utils/getErrorMessage';

/**
 * MDC文件解析结果
 */
export interface MdcParseResult {
  /** 元信息 */
  metaData: RuleMetaData;
  /** 内容 */
  content: string;
  /** 是否解析成功 */
  success: boolean;
  /** 错误信息 */
  error?: string;
}

/**
 * MDC文件解析器
 * 解析格式：
 * ---
 * description: xxx
 * globs: []
 * alwaysApply: true
 * ---
 * content
 */
export class MdcParser {
  private static readonly FRONT_MATTER_DELIMITER = '---';

  /**
   * 解析MDC格式文件内容
   */
  public static parse(content: string): MdcParseResult {
    try {
      // 统一换行符：将 CRLF 转为 LF，避免 \r 残留导致 YAML 解析异常
      const normalizedContent = content.replace(/\r\n/g, '\n');
      const trimmedContent = normalizedContent.trim();

      // 检查是否以front matter开始
      if (!trimmedContent.startsWith(MdcParser.FRONT_MATTER_DELIMITER)) {
        // 如果没有front matter，整个内容都是content
        return {
          metaData: {
            alwaysApply: false
          },
          content: content,
          success: true
        };
      }

      // 分割front matter和content
      const lines = trimmedContent.split('\n');
      if (lines.length < 3) {
        throw new Error('Invalid MDC format: insufficient lines');
      }

      // 查找第二个分隔符
      let frontMatterEnd = -1;
      for (let i = 1; i < lines.length; i++) {
        if (lines[i].trim() === MdcParser.FRONT_MATTER_DELIMITER) {
          frontMatterEnd = i;
          break;
        }
      }

      if (frontMatterEnd === -1) {
        throw new Error('Invalid MDC format: missing closing front matter delimiter');
      }

      // 提取front matter内容（去除分隔符行）
      const frontMatterLines = lines.slice(1, frontMatterEnd);
      const frontMatterContent = frontMatterLines.join('\n');

      // 提取content部分（去除front matter和分隔符）
      const contentLines = lines.slice(frontMatterEnd + 1);
      const contentPart = contentLines.join('\n').trim();

      // 解析YAML front matter
      const metaData = MdcParser.parseFrontMatter(frontMatterContent);

      return {
        metaData,
        content: contentPart,
        success: true
      };

    } catch (error) {
      const errorMessage = getErrorMessage(error);
      return {
        metaData: {
          alwaysApply: false
        },
        content: '',
        success: false,
        error: errorMessage
      };
    }
  }

  /**
   * 解析front matter YAML内容
   */
  private static parseFrontMatter(yamlContent: string): RuleMetaData {
    try {
      // 预处理：为了兼容Cursor风格的不带引号的globs字段，进行特殊处理
      let processedYamlContent = yamlContent;

      // 检查是否有不带引号的globs字段，如果有则为其添加引号
      const globsMatch = processedYamlContent.match(/^globs:\s*([^"'\n]+)$/gm);
      if (globsMatch) {
        for (const match of globsMatch) {
          const value = match.replace(/^globs:\s*/, '').trim();
          // 如果值不是以引号开始，则添加引号
          if (!value.startsWith('"') && !value.startsWith("'")) {
            processedYamlContent = processedYamlContent.replace(
              match,
              `globs: "${value}"`
            );
          }
        }
      }

      const parsed = yaml.parse(processedYamlContent) || {};

      const alwaysApply = Boolean(parsed.alwaysApply);

      // 提取并验证字段
      const metaData: RuleMetaData = {
        name: parsed.name ? parsed.name.trim() : undefined,
        description: parsed.description ? parsed.description.trim() : undefined,
        alwaysApply
      };

      // 处理globs字段 - 同时支持字符串和数组两种格式
      if (typeof parsed.globs === 'string') {
        // 支持 Cursor 风格：globs: "**/*.js,**/*.ts"
        const validGlobs = parsed.globs
          .split(',')
          .map((glob: string) => glob.trim())
          .filter((glob: string) => glob.length > 0);

        if (validGlobs.length > 0) {
          metaData.globs = validGlobs;
        } else {
          metaData.globs = [];
        }
      } else if (Array.isArray(parsed.globs)) {
        // 支持标准 YAML 数组风格：globs: ["**/*.js", "**/*.ts"]
        const validGlobs = parsed.globs
          .filter((glob: any) => typeof glob === 'string')
          .map((glob: string) => glob.trim())
          .filter((glob: string) => glob.length > 0);

        if (validGlobs.length > 0) {
          metaData.globs = validGlobs;
        } else {
          metaData.globs = [];
        }
      }
      return metaData;
    } catch (error) {
      // 如果YAML解析失败，返回默认值
      return {
        alwaysApply: false
      };
    }
  }

  /**
   * 将Rule对象转换为MDC格式字符串
   */
  public static stringify(metaData: RuleMetaData, content: string): string {
    try {
      // 构建front matter对象
      const frontMatterObj: Record<string, any> = {};

      if (metaData.name) {
        frontMatterObj.name = metaData.name;
      }

      if (metaData.description) {
        frontMatterObj.description = metaData.description;
      }

      // 只有当globs存在时才添加到YAML中，默认使用字符串格式（Cursor 风格）
      if (metaData.globs) {
        // 使用逗号分隔的字符串格式，与 Cursor 等产品保持一致
        // 注意：由于glob模式包含特殊字符(*等)，YAML需要双引号包围
        frontMatterObj.globs = metaData.globs.join(',');
      }

      frontMatterObj.alwaysApply = metaData.alwaysApply;

      // 生成YAML front matter
      const yamlContent = yaml.stringify(frontMatterObj, {
        indent: 2
      }).trim();

      // 特殊处理：移除globs字段的引号以保持与Cursor一致
      const processedYamlContent = yamlContent.replace(
        /^globs:\s*"([^"]+)"$/gm,
        'globs: $1'
      );

      // 组合完整的MDC内容
      const mdcContent = [
        MdcParser.FRONT_MATTER_DELIMITER,
        processedYamlContent,
        MdcParser.FRONT_MATTER_DELIMITER,
        content.trim()
      ].join('\n');

      return mdcContent;
    } catch (error) {
      throw new Error(`Failed to stringify MDC content: ${getErrorMessage(error)}`);
    }
  }

  /**
   * 验证MDC格式是否有效
   */
  public static validate(content: string): { valid: boolean; error?: string } {
    const result = MdcParser.parse(content);
    return {
      valid: result.success,
      error: result.error
    };
  }

  /**
   * 提取纯内容（不包含front matter）
   */
  public static extractContent(content: string): string {
    const result = MdcParser.parse(content);
    return result.content;
  }

  /**
   * 提取元信息
   */
  public static extractMetaData(content: string): RuleMetaData | null {
    const result = MdcParser.parse(content);
    return result.success ? result.metaData : null;
  }
}

export default MdcParser;
